import { test, expect } from "bun:test"
import { mkdir, readFile, stat, writeFile } from "node:fs/promises"
import path from "node:path"
import { getCliTestFixture } from "../../fixtures/get-cli-test-fixture"

// Regression test for https://github.com/tscircuit/tscircuit/issues/2550
// SVGs generated by --pcb-svgs / --schematic-svgs should be written to the
// component's subdirectory inside dist/, not to the dist root.

const circuitCode = `
export default () => (
  <board width="10mm" height="10mm">
    <resistor resistance="1k" footprint="0402" name="R1" schX={3} pcbX={3} />
  </board>
)`

test("build --pcb-svgs places pcb.svg alongside circuit.json in component subdir (issue #2550)", async () => {
  const { tmpDir, runCommand } = await getCliTestFixture()

  // Place the circuit file in a nested subdirectory (lib/components/MyComponent.tsx)
  const nestedDir = path.join(tmpDir, "lib", "components")
  await mkdir(nestedDir, { recursive: true })
  const circuitPath = path.join(nestedDir, "MyComponent.tsx")
  await writeFile(circuitPath, circuitCode)
  await writeFile(path.join(tmpDir, "package.json"), "{}")

  const { exitCode } = await runCommand(`tsci build --pcb-svgs ${circuitPath}`)
  expect(exitCode).toBe(0)

  // SVG must be in the component's output subdir, not at the dist root
  const expectedSvgPath = path.join(
    tmpDir,
    "dist",
    "lib",
    "components",
    "MyComponent",
    "pcb.svg",
  )
  const pcbSvg = await readFile(expectedSvgPath, "utf-8")
  expect(pcbSvg).toContain("<svg")

  // There should be no stray pcb.svg at dist root
  await expect(stat(path.join(tmpDir, "dist", "pcb.svg"))).rejects.toBeTruthy()
}, 30_000)

test("build --schematic-svgs places schematic.svg alongside circuit.json in component subdir (issue #2550)", async () => {
  const { tmpDir, runCommand } = await getCliTestFixture()

  const nestedDir = path.join(tmpDir, "lib", "components")
  await mkdir(nestedDir, { recursive: true })
  const circuitPath = path.join(nestedDir, "MyComponent.tsx")
  await writeFile(circuitPath, circuitCode)
  await writeFile(path.join(tmpDir, "package.json"), "{}")

  const { exitCode } = await runCommand(
    `tsci build --schematic-svgs ${circuitPath}`,
  )
  expect(exitCode).toBe(0)

  const expectedSvgPath = path.join(
    tmpDir,
    "dist",
    "lib",
    "components",
    "MyComponent",
    "schematic.svg",
  )
  const schSvg = await readFile(expectedSvgPath, "utf-8")
  expect(schSvg).toContain("<svg")

  // There should be no stray schematic.svg at dist root
  await expect(
    stat(path.join(tmpDir, "dist", "schematic.svg")),
  ).rejects.toBeTruthy()
}, 30_000)
